PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?eurCount ?czkCount (?eurCount / ?czkCount AS ?ratio) WHERE {
  {
    SELECT (COUNT(DISTINCT ?custE) AS ?eurCount) WHERE {
      ?custE <http://debitcard.org/schema#currency> "EUR" .
    }
  }
  {
    SELECT (COUNT(DISTINCT ?custC) AS ?czkCount) WHERE {
      ?custC <http://debitcard.org/schema#currency> "CZK" .
    }
  }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?customer ?total ?label WHERE {
  {
    SELECT ?customer (SUM(?value) AS ?total) ?label WHERE {
      ?cons rdf:type <http://debitcard.org/schema#MonthlyConsumption> ;
            <http://debitcard.org/schema#consumptionValue> ?value ;
            <http://debitcard.org/schema#date> ?date ;
            <http://debitcard.org/schema#forCustomer> ?customer .
      ?customer <http://debitcard.org/schema#segment> "LAM" .
      OPTIONAL { ?customer rdfs:label ?label. }
      FILTER( STRSTARTS(STR(?date), "2012") )
    }
    GROUP BY ?customer ?label
  }
  {
    SELECT (MIN(?t) AS ?minTotal) WHERE {
      SELECT (SUM(?value) AS ?t) WHERE {
        ?cons rdf:type <http://debitcard.org/schema#MonthlyConsumption> ;
              <http://debitcard.org/schema#consumptionValue> ?value ;
              <http://debitcard.org/schema#date> ?date ;
              <http://debitcard.org/schema#forCustomer> ?cust2 .
        ?cust2 <http://debitcard.org/schema#segment> "LAM" .
        FILTER( STRSTARTS(STR(?date), "2012") )
      }
      GROUP BY ?cust2
    }
  }
  FILTER(?total = ?minTotal)
}

SELECT ?czk_total ?eur_total ?difference WHERE {
  {
    SELECT (SUM(?v) AS ?czk_total) WHERE {
      ?mc rdf:type <http://debitcard.org/schema#MonthlyConsumption> ;
          <http://debitcard.org/schema#consumptionValue> ?v ;
          <http://debitcard.org/schema#date> ?date ;
          <http://debitcard.org/schema#forCustomer> ?cust .
      ?cust <http://debitcard.org/schema#currency> "CZK" .
      FILTER(STRSTARTS(STR(?date), "2012"))
    }
  }
  {
    SELECT (SUM(?v2) AS ?eur_total) WHERE {
      ?mc2 rdf:type <http://debitcard.org/schema#MonthlyConsumption> ;
           <http://debitcard.org/schema#consumptionValue> ?v2 ;
           <http://debitcard.org/schema#date> ?date2 ;
           <http://debitcard.org/schema#forCustomer> ?cust2 .
      ?cust2 <http://debitcard.org/schema#currency> "EUR" .
      FILTER(STRSTARTS(STR(?date2), "2012"))
    }
  }
  BIND((?czk_total - ?eur_total) AS ?difference)
}

SELECT ?year (SUM(?totalPrice) AS ?sum) WHERE {
  ?tx a <http://debitcard.org/schema#Transaction> ;
      <http://debitcard.org/schema#date> ?date ;
      <http://debitcard.org/schema#atStation> ?gs ;
      <http://debitcard.org/schema#totalPrice> ?totalPrice ;
      <http://debitcard.org/schema#madeBy> ?cust .
  ?gs a <http://debitcard.org/schema#GasStation> .
  ?cust <http://debitcard.org/schema#currency> "CZK" .
  BIND(YEAR(?date) AS ?year)
}
GROUP BY ?year
ORDER BY DESC(?sum)
LIMIT 1

SELECT ?ym (SUM(xsd:decimal(?consValue)) AS ?totalConsumption) WHERE {
  ?cons a <http://debitcard.org/schema#MonthlyConsumption> ;
        <http://debitcard.org/schema#date> ?ym ;
        <http://debitcard.org/schema#consumptionValue> ?consValue ;
        <http://debitcard.org/schema#forCustomer> ?c .
  ?c <http://debitcard.org/schema#segment> ?seg .
  FILTER(strstarts(str(?ym), "2013"))
  FILTER(?seg = "SME")
}
GROUP BY ?ym
ORDER BY DESC(?totalConsumption)
LIMIT 1

SELECT ?sme_avg ?lam_avg ?kam_avg (?sme_avg - ?lam_avg AS ?SME_minus_LAM) (?lam_avg - ?kam_avg AS ?LAM_minus_KAM) (?kam_avg - ?sme_avg AS ?KAM_minus_SME) WHERE {
  {
    SELECT (MAX(IF(?segment="SME", ?annual_avg, 0)) AS ?sme_avg) (MAX(IF(?segment="LAM", ?annual_avg, 0)) AS ?lam_avg) (MAX(IF(?segment="KAM", ?annual_avg, 0)) AS ?kam_avg)
    WHERE {
      {
        SELECT ?segment ?annual_avg WHERE {
          {
            SELECT ?cust ?segment (SUM(?val) AS ?sum2013) (AVG(?val) AS ?avg_month) ((AVG(?val)*12) AS ?annual_avg)
            WHERE {
              ?consumption a <http://debitcard.org/schema#MonthlyConsumption> ;
                <http://debitcard.org/schema#consumptionValue> ?val ;
                <http://debitcard.org/schema#forCustomer> ?cust ;
                <http://debitcard.org/schema#date> ?date .
              ?cust <http://debitcard.org/schema#segment> ?segment ;
                    <http://debitcard.org/schema#currency> "CZK" .
              FILTER(?segment IN ("SME","LAM","KAM"))
              FILTER(STRSTARTS(STR(?date),"2013"))
            }
            GROUP BY ?cust ?segment
          }
          {
            SELECT ?segment (MIN(?sum2013_) AS ?minSum) WHERE {
              {
                SELECT ?cust2 ?segment (SUM(?val2) AS ?sum2013_) WHERE {
                  ?cons2 <http://debitcard.org/schema#consumptionValue> ?val2 ;
                    <http://debitcard.org/schema#forCustomer> ?cust2 ;
                    <http://debitcard.org/schema#date> ?date2 .
                  ?cust2 <http://debitcard.org/schema#segment> ?segment ;
                         <http://debitcard.org/schema#currency> "CZK" .
                  FILTER(?segment IN ("SME","LAM","KAM"))
                  FILTER(STRSTARTS(STR(?date2),"2013"))
                } GROUP BY ?cust2 ?segment
              }
            } GROUP BY ?segment
          }
          FILTER(?sum2013 = ?minSum)
        }
      }
    }
  }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX sc: <http://debitcard.org/schema#>
SELECT ?segment 
       (SUM(IF(SUBSTR(STR(?date),1,4) = "2012", ?value, 0)) AS ?sum2012)
       (SUM(IF(SUBSTR(STR(?date),1,4) = "2013", ?value, 0)) AS ?sum2013)
       ( ((SUM(IF(SUBSTR(STR(?date),1,4) = "2013", ?value, 0)) - SUM(IF(SUBSTR(STR(?date),1,4) = "2012", ?value, 0)))
           / SUM(IF(SUBSTR(STR(?date),1,4) = "2012", ?value, 0))) * 100 AS ?pctIncrease)
WHERE {
  ?cons rdf:type sc:MonthlyConsumption ;
        sc:consumptionValue ?value ;
        sc:date ?date ;
        sc:forCustomer ?cust .
  ?cust sc:segment ?segment ;
        sc:currency "EUR" .
}
GROUP BY ?segment
HAVING (SUM(IF(SUBSTR(STR(?date),1,4) = "2012", ?value, 0)) > 0)
ORDER BY DESC(?pctIncrease)

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (SUM(?consVal) AS ?total) WHERE {
  ?cons <http://debitcard.org/schema#forCustomer> <http://debitcard.org/customer/6> ;
        <http://debitcard.org/schema#date> ?date ;
        <http://debitcard.org/schema#consumptionValue> ?consVal .
  FILTER(xsd:integer(?date) >= 201308 && xsd:integer(?date) <= 201311)
}

SELECT ?czeCount ?svkCount ?difference WHERE {
  { SELECT (COUNT(DISTINCT ?gsCZE) AS ?czeCount) WHERE {
      ?gsCZE <http://debitcard.org/schema#segment> "Discount" .
      ?gsCZE <http://debitcard.org/schema#country> "CZE" .
    }
  }
  { SELECT (COUNT(DISTINCT ?gsSVK) AS ?svkCount) WHERE {
      ?gsSVK <http://debitcard.org/schema#segment> "Discount" .
      ?gsSVK <http://debitcard.org/schema#country> "SVK" .
    }
  }
  BIND((?czeCount - ?svkCount) AS ?difference)
}

SELECT ?czkCount ?eurCount (?czkCount - ?eurCount AS ?difference) WHERE {
  {
    SELECT (COUNT(DISTINCT ?c1) AS ?czkCount) WHERE {
      ?c1 <http://debitcard.org/schema#segment> "SME" ;
          <http://debitcard.org/schema#currency> "CZK" .
    }
  }
  {
    SELECT (COUNT(DISTINCT ?c2) AS ?eurCount) WHERE {
      ?c2 <http://debitcard.org/schema#segment> "SME" ;
          <http://debitcard.org/schema#currency> "EUR" .
    }
  }
}

SELECT ?num_high ?num_total ?percent WHERE {
  {
    SELECT (COUNT(DISTINCT ?c_high) AS ?num_high)
    WHERE {
      ?c_high <http://debitcard.org/schema#segment> "LAM" .
      ?consumption <http://debitcard.org/schema#forCustomer> ?c_high ;
                   <http://debitcard.org/schema#consumptionValue> ?val .
      FILTER(xsd:decimal(?val) > 46.73)
    }
  }
  {
    SELECT (COUNT(DISTINCT ?c_total) AS ?num_total)
    WHERE {
      ?c_total <http://debitcard.org/schema#segment> "LAM" .
    }
  }
  BIND( (xsd:decimal(?num_high) * 100.0) / xsd:decimal(?num_total) AS ?percent )
}

SELECT (IF(?total = 0, 0, (?high * 100.0) / ?total) AS ?percentage) WHERE {
  {
    SELECT (COUNT(DISTINCT ?cust) AS ?total) WHERE {
      ?cons rdf:type <http://debitcard.org/schema#MonthlyConsumption> ;
            <http://debitcard.org/schema#date> "201202" ;
            <http://debitcard.org/schema#forCustomer> ?cust .
    }
  }
  {
    SELECT (COUNT(DISTINCT ?cust2) AS ?high) WHERE {
      ?cons2 rdf:type <http://debitcard.org/schema#MonthlyConsumption> ;
            <http://debitcard.org/schema#date> "201202" ;
            <http://debitcard.org/schema#forCustomer> ?cust2 ;
            <http://debitcard.org/schema#consumptionValue> ?value2 .
      FILTER(?value2 > 528.3)
    }
  }
}

SELECT ?s ?value ?label WHERE {
  ?s rdf:type <http://debitcard.org/schema#MonthlyConsumption> ;
     <http://debitcard.org/schema#consumptionValue> ?value .
  FILTER(regex(str(?s), "-2012"))
  OPTIONAL { ?s rdfs:label ?label }
  {
    SELECT (MAX(?v) AS ?max) WHERE {
      ?x rdf:type <http://debitcard.org/schema#MonthlyConsumption> ;
         <http://debitcard.org/schema#consumptionValue> ?v .
      FILTER(regex(str(?x), "-2012"))
    }
  }
  FILTER(?value = ?max)
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?product ?productDescription ?productLabel WHERE {
  ?transaction <http://debitcard.org/schema#includesProduct> ?product .
  ?transaction <http://debitcard.org/schema#date> ?date .
  FILTER( 
    (datatype(?date) = xsd:date && YEAR(?date)=2013 && MONTH(?date)=9)
    || (STR(?date) = "201309")
    || STRSTARTS(STR(?date), "2013-09")
  ) .
  ?product <http://debitcard.org/schema#productDescription> ?productDescription .
  OPTIONAL { ?product rdfs:label ?productLabel }
} ORDER BY ?productDescription

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?station ?country WHERE {
  ?tx <http://debitcard.org/schema#atStation> ?station ;
      <http://debitcard.org/schema#date> ?date .
  ?station <http://debitcard.org/schema#country> ?country .
  FILTER(xsd:date(?date) >= "2013-06-01"^^xsd:date && xsd:date(?date) < "2013-07-01"^^xsd:date)
} ORDER BY ?country

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?customer) AS ?count)
WHERE {
  ?customer <http://debitcard.org/schema#currency> "EUR" .
  ?consumption <http://debitcard.org/schema#forCustomer> ?customer ;
               <http://debitcard.org/schema#consumptionValue> ?val .
  FILTER(?val > "1000"^^xsd:decimal)
}

SELECT DISTINCT ?product ?productDescription WHERE {
  ?tx <http://debitcard.org/schema#includesProduct> ?product .
  ?tx <http://debitcard.org/schema#atStation> ?station .
  ?station <http://debitcard.org/schema#country> "CZE" .
  ?product <http://debitcard.org/schema#productDescription> ?productDescription .
} ORDER BY ?productDescription

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?tx ?customer ?currency WHERE {
  ?tx rdf:type <http://debitcard.org/schema#Transaction> ;
      <http://debitcard.org/schema#date> "2012-08-24"^^xsd:date ;
      <http://debitcard.org/schema#time> "16:25:00" ;
      <http://debitcard.org/schema#madeBy> ?customer .
  ?customer <http://debitcard.org/schema#currency> ?currency .
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?customer ?country WHERE {
  ?txn rdf:type <http://debitcard.org/schema#Transaction> ;
       <http://debitcard.org/schema#date> "2012-08-24"^^xsd:date ;
       <http://debitcard.org/schema#madeBy> ?customer .
  {
    ?txn <http://debitcard.org/schema#pricePerUnit> 548.4 .
  }
  UNION
  {
    ?txn <http://debitcard.org/schema#consumptionValue> 548.4 .
  }
  UNION
  {
    ?txn <http://debitcard.org/schema#amount> 548.4 .
  }
  OPTIONAL { ?customer <http://debitcard.org/schema#country> ?country . }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?eur_count ?total_count ?percent WHERE {
  {
    SELECT (COUNT(DISTINCT ?cust) AS ?total_count)
    WHERE {
      ?tx <http://debitcard.org/schema#date> "2012-08-25"^^xsd:date ;
          <http://debitcard.org/schema#madeBy> ?cust .
    }
  }
  {
    SELECT (COUNT(DISTINCT ?cust2) AS ?eur_count)
    WHERE {
      ?tx2 <http://debitcard.org/schema#date> "2012-08-25"^^xsd:date ;
           <http://debitcard.org/schema#madeBy> ?cust2 .
      ?cust2 <http://debitcard.org/schema#currency> "EUR" .
    }
  }
  BIND( IF(?total_count = 0, 0, ((xsd:decimal(?eur_count) * 100.0) / xsd:decimal(?total_count))) AS ?percent )
}
